mapper.select:
SELECT s.id, s.title, s.category, CASE s.category WHEN 1 THEN '奇幻校园' WHEN 2 THEN '悬疑推理' WHEN 3 THEN '浪漫物语' WHEN 4 THEN '搞笑日常' WHEN 5 THEN '科幻未来' ELSE '未知' END AS categoryName, s.status, CASE s.status WHEN 1 THEN '进行中' WHEN 2 THEN '已完结' WHEN 3 THEN '已归档' ELSE '未知' END AS statusName, s.paragraph_count AS paragraphCount, s.participant_count AS participantCount, s.total_likes AS totalLikes, s.is_recommended AS isRecommended, s.creator_id AS creatorId, u.nickname AS creatorNickname, u.avatar AS creatorAvatar, s.create_time AS createTime, LEFT(s.first_paragraph, 100) AS firstParagraphPreview FROM story s LEFT JOIN sys_user u ON s.creator_id = u.id
AND s.category = #{category}
AND s.status = #{status}
AND (s.title LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY s.is_recommended DESC, s.create_time DESC
